#include <stdio.h>

static const int *remember(int value) {
    static int stored;
    stored = value;
    return &stored;
}

int main(void) {
    int first, second;
    if (scanf("%d %d", &first, &second) != 2) return 1;
    const int *address = remember(first);
    printf("%d ", *address);
    address = remember(second);
    printf("%d\n", *address);
    return 0;
}
